from datetime import datetime
from typing import Optional

from pydantic import BaseModel, Field


class BehaviorEntities(BaseModel):
    AccountDomain: Optional[str] = Field(None, description="Domain of the account.")
    AccountName: Optional[str] = Field(None, description="User name of the account.")
    AccountObjectId: Optional[str] = Field(None, description="Unique identifier for the account in Azure AD.")
    AccountSid: Optional[str] = Field(None, description="Security Identifier (SID) of the account.")
    AccountUpn: Optional[str] = Field(None, description="User principal name (UPN) of the account.")
    ActionType: Optional[str] = Field(None, description="Type of activity that triggered the event. Associated with specific MITRE ATT&CK techniques.")
    AdditionalFields: Optional[str] = Field(None, description="Additional information about the entity or event.")
    Application: Optional[str] = Field(None, description="Application that performed the recorded action.")
    ApplicationId: Optional[str] = Field(None, description="Unique identifier for the application.")
    BehaviorId: Optional[str] = Field(None, description="Unique identifier for the behavior.")
    Categories: Optional[str] = Field(None, description="Types of threat indicator or breach activity identified by the alert. Defined by the MITRE ATT&CK Matrix for Enterprise.")
    DataSources: Optional[str] = Field(None, description="Products or services that provided information for the behavior.")
    DetailedEntityRole: Optional[str] = Field(None, description="The role of the entity in the behavior")
    DetectionSource: Optional[str] = Field(None, description="Detection technology or sensor that identified the notable component or activity.")
    DeviceId: Optional[str] = Field(None, description="Unique identifier for the device in the service.")
    DeviceName: Optional[str] = Field(None, description="Fully qualified domain name (FQDN) of the device.")
    EmailClusterId: Optional[str] = Field(None, description="Identifier for the group of similar emails clustered based on heuristic analysis of their contents.")
    EmailSubject: Optional[str] = Field(None, description="Subject of the email.")
    EntityRole: Optional[str] = Field(None, description="Indicates whether the entity is impacted or merely related.")
    EntityType: Optional[str] = Field(None, description="Type of object, such as a file, a process, a device, or a user.")
    FileName: Optional[str] = Field(None, description="Name of the file involved in the alert. Empty unless EntityType is \"File\" or \"Process\".")
    FileSize: Optional[int] = Field(None, description="Size of the file in bytes. Empty unless EntityType is \"File\" or \"Process\"")
    FolderPath: Optional[str] = Field(None, description="Folder containing the file. Empty unless EntityType is \"File\" or \"Process\".")
    LocalIP: Optional[str] = Field(None, description="IP address assigned to the local machine used during communication.")
    NetworkMessageId: Optional[str] = Field(None, description="Unique identifier for the email in UUID format, generated by Office 365.")
    OAuthApplicationId: Optional[str] = Field(None, description="Unique identifier of the third-party OAuth application in UUID format.")
    ProcessCommandLine: Optional[str] = Field(None, description="Command line used to create the new process.")
    RegistryKey: Optional[str] = Field(None, description="Registry key that the recorded action was applied to.")
    RegistryValueData: Optional[str] = Field(None, description="Data of the registry value that the recorded action was applied to.")
    RegistryValueName: Optional[str] = Field(None, description="Name of the registry value that the recorded action was applied to.")
    RemoteIP: Optional[str] = Field(None, description="IP address that was being connected to.")
    RemoteUrl: Optional[str] = Field(None, description="URL or fully qualified domain name (FQDN) that was being connected to.")
    ServiceSource: Optional[str] = Field(None, description="Product or service that provided the alert information.")
    SHA1: Optional[str] = Field(None, description="SHA-1 hash of the file. Empty unless EntityType is \"File\" or \"Process\".")
    SHA256: Optional[str] = Field(None, description="SHA-256 of the file. Empty unless EntityType is \"File\" or \"Process\".")
    SourceSystem: Optional[str] = Field(None, description="The type of agent the event was collected by. For example,OpsManagerfor Windows agent, either direct connect or Operations Manager,Linuxfor all Linux agents, orAzurefor Azure Diagnostics")
    TenantId: Optional[str] = Field(None, description="The Log Analytics workspace ID")
    ThreatFamily: Optional[str] = Field(None, description="Malware family that the suspicious or malicious file or process has been classified under.")
    TimeGenerated: Optional[datetime] = Field(None, description="Date and time when the record was generated.")
    Type: Optional[str] = Field(None, description="The name of the table")
